/* Minimal Python syntax highlighter — no external dependencies */
(function (global) {
  var KW = new Set([
    "False","None","True","and","as","assert","async","await","break",
    "class","continue","def","del","elif","else","except","finally",
    "for","from","global","if","import","in","is","lambda","nonlocal",
    "not","or","pass","raise","return","try","while","with","yield"
  ]);
  var BUILTIN = new Set([
    "abs","all","any","ascii","bin","bool","breakpoint","bytearray","bytes",
    "callable","chr","classmethod","compile","complex","copyright","delattr",
    "dict","dir","divmod","enumerate","eval","exec","filter","float","format",
    "frozenset","getattr","globals","hasattr","hash","help","hex","id","input",
    "int","isinstance","issubclass","iter","len","list","locals","map","max",
    "memoryview","min","next","object","oct","open","ord","pow","print",
    "property","range","repr","reversed","round","set","setattr","slice",
    "sorted","staticmethod","str","sum","super","tuple","type","vars","zip"
  ]);

  function esc(s) {
    return s.replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;");
  }

  /* Returns index of # comment start, -1 if none (handles quoted strings) */
  function commentStart(line) {
    var inStr = false, q = "";
    for (var i = 0; i < line.length; i++) {
      var c = line[i];
      if (inStr) {
        if (c === "\\" ) { i++; continue; }
        if (c === q)    { inStr = false; }
      } else {
        if (c === "#")  { return i; }
        if (c === '"' || c === "'") { inStr = true; q = c; }
      }
    }
    return -1;
  }

  function tokeniseLine(src) {
    var out = [], i = 0;
    while (i < src.length) {
      var c = src[i];
      /* Triple-quoted string */
      if ((c === '"' || c === "'") && src.slice(i, i+3) === c+c+c) {
        var q3 = c+c+c, end = src.indexOf(q3, i+3);
        var s = end >= 0 ? src.slice(i, end+3) : src.slice(i);
        out.push('<span class="py-str">'+esc(s)+'</span>');
        i = end >= 0 ? end+3 : src.length;
      /* Single-quoted string */
      } else if (c === '"' || c === "'") {
        var j = i+1;
        while (j < src.length && src[j] !== c) { if (src[j]==="\\") j++; j++; }
        var s2 = src.slice(i, Math.min(j+1, src.length));
        out.push('<span class="py-str">'+esc(s2)+'</span>');
        i = Math.min(j+1, src.length);
      /* Number */
      } else if (/\d/.test(c) || (c==="." && /\d/.test(src[i+1]||""))) {
        var k = i;
        while (k < src.length && /[\d._xXbBoOeEjJ]/.test(src[k])) k++;
        out.push('<span class="py-num">'+esc(src.slice(i,k))+'</span>');
        i = k;
      /* Word */
      } else if (/[a-zA-Z_]/.test(c)) {
        var m = i;
        while (m < src.length && /\w/.test(src[m])) m++;
        var word = src.slice(i, m);
        if (KW.has(word)) {
          out.push('<span class="py-kw">'+esc(word)+'</span>');
        } else if (BUILTIN.has(word)) {
          out.push('<span class="py-bi">'+esc(word)+'</span>');
        } else if (src[m] === "(") {
          out.push('<span class="py-fn">'+esc(word)+'</span>');
        } else if (word === word.toUpperCase() && word.length > 1 && /[A-Z]/.test(word[0])) {
          out.push('<span class="py-const">'+esc(word)+'</span>');
        } else {
          out.push(esc(word));
        }
        i = m;
      } else if (c === "@") {
        var n = i+1;
        while (n < src.length && /[\w.]/.test(src[n])) n++;
        out.push('<span class="py-dec">'+esc(src.slice(i,n))+'</span>');
        i = n;
      } else {
        out.push(esc(c));
        i++;
      }
    }
    return out.join("");
  }

  function highlight(code) {
    return code.split("\n").map(function(line) {
      var ci = commentStart(line);
      if (ci >= 0) {
        return tokeniseLine(line.slice(0, ci))
          + '<span class="py-cmt">'+esc(line.slice(ci))+'</span>';
      }
      return tokeniseLine(line);
    }).join("\n");
  }

  global.pyHighlight = { highlight: highlight };
}(window));
